      overflow: hidden;
      margin: 16px 0;
    }
    pre .code-lang {
      display: block;
      padding: 6px 16px;
      background: #0d1117;
      border-bottom: 1px solid var(--border);
      font-family: monospace;
      font-size: 11px;
