     1→/**
     2→ * 마크다운 파서 - 외부 라이브러리 없이 직접 구현
     3→ * 지원: 제목, 굵게, 기울임, 인라인 코드, 코드블록, 링크, 이미지,
     4→ *       순서/비순서 목록(중첩), 인용문(중첩), 수평선, 문단, 줄바꿈, 이스케이프
     5→ */
     6→
     7→const MarkdownParser = (() => {
     8→  // 이스케이프 처리가 필요한 HTML 특수문자
     9→  function escapeHtml(text) {
    10→    return text
    11→      .replace(/&/g, '&amp;')
    12→      .replace(/</g, '&lt;')
    13→      .replace(/>/g, '&gt;')
    14→      .replace(/"/g, '&quot;')
    15→      .replace(/'/g, '&#39;');
    16→  }
    17→
    18→  // 백슬래시 이스케이프 처리
    19→  function processEscapes(text) {
    20→    return text.replace(/\\([\\`*_{}\[\]()#+\-.!~|])/g, (_, char) => {
    21→      return `&#x${char.charCodeAt(0).toString(16)};`;
    22→    });
    23→  }
    24→
    25→  // 인라인 요소 파싱 (굵게, 기울임, 인라인 코드, 링크, 이미지)
    26→  function parseInline(text) {
    27→    // 백슬래시 이스케이프 먼저 처리
    28→    text = processEscapes(text);
    29→
    30→    // 인라인 코드 (`` ` `` 또는 ` `` `)
    31→    text = text.replace(/``(.+?)``/g, (_, code) => `<code>${escapeHtml(code)}</code>`);
    32→    text = text.replace(/`([^`]+)`/g, (_, code) => `<code>${escapeHtml(code)}</code>`);
    33→
    34→    // 이미지 (링크보다 먼저 처리)
    35→    text = text.replace(/!\[([^\]]*)\]\(([^)]+?)(?:\s+"([^"]*)")?\)/g, (_, alt, src, title) => {
    36→      const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
    37→      return `<img src="${escapeHtml(src)}" alt="${escapeHtml(alt)}"${titleAttr}>`;
    38→    });
    39→
    40→    // 링크
    41→    text = text.replace(/\[([^\]]+)\]\(([^)]+?)(?:\s+"([^"]*)")?\)/g, (_, label, href, title) => {
    42→      const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
    43→      return `<a href="${escapeHtml(href)}"${titleAttr}>${label}</a>`;
    44→    });
    45→
    46→    // 굵게 + 기울임 (***text*** 또는 ___text___)
    47→    text = text.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
    48→    text = text.replace(/___(.+?)___/g, '<strong><em>$1</em></strong>');
    49→
    50→    // 굵게 (**text** 또는 __text__)
    51→    text = text.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    52→    text = text.replace(/__(.+?)__/g, '<strong>$1</strong>');
    53→
    54→    // 기울임 (*text* 또는 _text_)
    55→    text = text.replace(/\*([^*]+)\*/g, '<em>$1</em>');
    56→    text = text.replace(/_([^_]+)_/g, '<em>$1</em>');
    57→
    58→    // 취소선 (~~text~~)
    59→    text = text.replace(/~~(.+?)~~/g, '<del>$1</del>');
    60→
    61→    // 자동 URL 링크
    62→    text = text.replace(/(https?:\/\/[^\s<>"]+)/g, '<a href="$1">$1</a>');
    63→
    64→    return text;
    65→  }
    66→
    67→  // 코드블록 추출 (파싱 전 플레이스홀더로 대체)
    68→  function extractCodeBlocks(lines) {
    69→    const codeBlocks = [];
    70→    const result = [];
    71→    let inCodeBlock = false;
    72→    let codeLines = [];
    73→    let codeLang = '';
    74→
    75→    for (let i = 0; i < lines.length; i++) {
    76→      const line = lines[i];
    77→      const fenceMatch = line.match(/^(`{3,}|~{3,})\s*(\w*)/);
    78→
    79→      if (!inCodeBlock && fenceMatch) {
    80→        inCodeBlock = true;
    81→        codeLang = fenceMatch[2] || '';
    82→        codeLines = [];
    83→      } else if (inCodeBlock && line.match(/^(`{3,}|~{3,})\s*$/)) {
    84→        inCodeBlock = false;
    85→        const placeholder = `\x00CODE_BLOCK_${codeBlocks.length}\x00`;
    86→        const langLabel = codeLang ? `<span class="code-lang">${escapeHtml(codeLang)}</span>` : '';
    87→        const codeContent = escapeHtml(codeLines.join('\n'));
    88→        codeBlocks.push(`<pre>${langLabel}<code class="language-${escapeHtml(codeLang)}">${codeContent}</code></pre>`);
    89→        result.push(placeholder);
    90→        codeLines = [];
    91→        codeLang = '';
    92→      } else if (inCodeBlock) {
    93→        codeLines.push(line);
    94→      } else {
    95→        result.push(line);
    96→      }
    97→    }
    98→
    99→    // 닫히지 않은 코드블록 처리
   100→    if (inCodeBlock && codeLines.length > 0) {
   101→      const placeholder = `\x00CODE_BLOCK_${codeBlocks.length}\x00`;
   102→      const langLabel = codeLang ? `<span class="code-lang">${escapeHtml(codeLang)}</span>` : '';
   103→      const codeContent = escapeHtml(codeLines.join('\n'));
   104→      codeBlocks.push(`<pre>${langLabel}<code class="language-${escapeHtml(codeLang)}">${codeContent}</code></pre>`);
   105→      result.push(placeholder);
   106→    }
   107→
   108→    return { lines: result, codeBlocks };
   109→  }
   110→
   111→  // 목록 파싱 (중첩 지원)
   112→  function parseList(lines, startIndex) {
   113→    const items = [];
   114→    let i = startIndex;
   115→    const firstLine = lines[i];
   116→    const isOrdered = /^\d+\.\s/.test(firstLine);
   117→    const baseIndent = firstLine.match(/^(\s*)/)[1].length;
   118→
   119→    while (i < lines.length) {
   120→      const line = lines[i];
   121→      if (line.trim() === '') {
   122→        i++;
   123→        break;
   124→      }
   125→
   126→      const indentMatch = line.match(/^(\s*)/);
   127→      const indent = indentMatch ? indentMatch[1].length : 0;
   128→
   129→      if (indent < baseIndent) break;
   130→
   131→      const ulMatch = line.match(/^(\s*)[-*+]\s+(.*)/);
   132→      const olMatch = line.match(/^(\s*)\d+\.\s+(.*)/);
   133→      const match = ulMatch || olMatch;
   134→
   135→      if (!match || match[1].length !== baseIndent) {
   136→        // 하위 항목이거나 다른 구조
   137→        if (indent > baseIndent && items.length > 0) {
   138→          const lastItem = items[items.length - 1];
   139→          const subResult = parseList(lines, i);
   140→          lastItem.children = subResult.html;
   141→          i = subResult.nextIndex;
   142→        } else {
   143→          break;
   144→        }
   145→        continue;
   146→      }
   147→
   148→      items.push({ text: match[2], children: null });
   149→      i++;
   150→
   151→      // 중첩 목록 확인
   152→      if (i < lines.length) {
   153→        const nextLine = lines[i];
   154→        const nextIndent = nextLine.match(/^(\s*)/)[1].length;
   155→        if (nextIndent > baseIndent && (nextLine.match(/^\s*[-*+]\s/) || nextLine.match(/^\s*\d+\.\s/))) {
   156→          const subResult = parseList(lines, i);
   157→          items[items.length - 1].children = subResult.html;
   158→          i = subResult.nextIndex;
   159→        }
   160→      }
   161→    }
   162→
   163→    const tag = isOrdered ? 'ol' : 'ul';
   164→    const html = `<${tag}>\n${items.map(item => {
   165→      const childContent = item.children ? `\n${item.children}` : '';
   166→      return `<li>${parseInline(item.text)}${childContent}</li>`;
   167→    }).join('\n')}\n</${tag}>`;
   168→
   169→    return { html, nextIndex: i };
   170→  }
   171→
   172→  // 인용문 파싱 (중첩 지원)
   173→  function parseBlockquote(lines, startIndex) {
   174→    const quoteLines = [];
   175→    let i = startIndex;
   176→
   177→    while (i < lines.length) {
   178→      const line = lines[i];
   179→      if (/^>/.test(line)) {
   180→        quoteLines.push(line.replace(/^>\s?/, ''));
   181→        i++;
   182→      } else if (line.trim() === '' && i + 1 < lines.length && /^>/.test(lines[i + 1])) {
   183→        quoteLines.push('');
   184→        i++;
   185→      } else {
   186→        break;
   187→      }
   188→    }
   189→
   190→    // 재귀적으로 인용문 내부 파싱
   191→    const innerHtml = parse(quoteLines.join('\n'));
   192→    return { html: `<blockquote>\n${innerHtml}\n</blockquote>`, nextIndex: i };
   193→  }
   194→
   195→  // 메인 파싱 함수
   196→  function parse(markdown) {
   197→    if (!markdown) return '';
   198→
   199→    // 줄 단위로 분리
   200→    const rawLines = markdown.split('\n');
   201→
   202→    // 코드블록 먼저 추출
   203→    const { lines, codeBlocks } = extractCodeBlocks(rawLines);
   204→
   205→    const outputParts = [];
   206→    let i = 0;
   207→    let paragraphLines = [];
   208→
   209→    function flushParagraph() {
   210→      if (paragraphLines.length === 0) return;
   211→      const content = paragraphLines.join('\n');
   212→      // 줄바꿈 처리 (두 스페이스 + 줄바꿈 → <br>)
   213→      const processed = content
   214→        .replace(/  \n/g, '<br>\n')
   215→        .replace(/\\\n/g, '<br>\n');
   216→      outputParts.push(`<p>${parseInline(processed)}</p>`);
   217→      paragraphLines = [];
   218→    }
   219→
   220→    while (i < lines.length) {
   221→      const line = lines[i];
   222→
   223→      // 코드블록 플레이스홀더
   224→      if (/^\x00CODE_BLOCK_\d+\x00$/.test(line)) {
   225→        flushParagraph();
   226→        const idx = parseInt(line.match(/\d+/)[0]);
   227→        outputParts.push(codeBlocks[idx]);
   228→        i++;
   229→        continue;
   230→      }
   231→
   232→      // 빈 줄
   233→      if (line.trim() === '') {
   234→        flushParagraph();
   235→        i++;
   236→        continue;
   237→      }
   238→
   239→      // ATX 제목 (# ~ ######)
   240→      const headingMatch = line.match(/^(#{1,6})\s+(.+?)(?:\s+#+)?$/);
   241→      if (headingMatch) {
   242→        flushParagraph();
   243→        const level = headingMatch[1].length;
   244→        const text = headingMatch[2];
   245→        const id = text.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
   246→        outputParts.push(`<h${level} id="${id}">${parseInline(text)}</h${level}>`);
   247→        i++;
   248→        continue;
   249→      }
   250→
   251→      // Setext 제목 (다음 줄이 === 또는 ---)
   252→      if (i + 1 < lines.length) {
   253→        const nextLine = lines[i + 1];
   254→        if (/^=+\s*$/.test(nextLine) && line.trim()) {
   255→          flushParagraph();
   256→          const id = line.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
   257→          outputParts.push(`<h1 id="${id}">${parseInline(line.trim())}</h1>`);
   258→          i += 2;
   259→          continue;
   260→        }
   261→        if (/^-+\s*$/.test(nextLine) && line.trim() && !(/^[-*+]\s/.test(line))) {
   262→          flushParagraph();
   263→          const id = line.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
   264→          outputParts.push(`<h2 id="${id}">${parseInline(line.trim())}</h2>`);
   265→          i += 2;
   266→          continue;
   267→        }
   268→      }
   269→
   270→      // 수평선 (---, ***, ___)
   271→      if (/^(\s*[-*_]){3,}\s*$/.test(line) && !(/^[-*+]\s/.test(line))) {
   272→        flushParagraph();
   273→        outputParts.push('<hr>');
   274→        i++;
   275→        continue;
   276→      }
   277→
   278→      // 인용문
   279→      if (/^>/.test(line)) {
   280→        flushParagraph();
   281→        const result = parseBlockquote(lines, i);
   282→        outputParts.push(result.html);
   283→        i = result.nextIndex;
   284→        continue;
   285→      }
   286→
   287→      // 목록
   288→      if (/^(\s*)[-*+]\s/.test(line) || /^(\s*)\d+\.\s/.test(line)) {
   289→        flushParagraph();
   290→        const result = parseList(lines, i);
   291→        outputParts.push(result.html);
   292→        i = result.nextIndex;
   293→        continue;
   294→      }
   295→
   296→      // 일반 텍스트 → 문단으로 수집
   297→      paragraphLines.push(line);
   298→      i++;
   299→    }
   300→
   301→    flushParagraph();
   302→
   303→    return outputParts.join('\n');
   304→  }
   305→
   306→  return { parse, parseInline, escapeHtml };
   307→})();
   308→

