// 인라인 요소 파싱 (굵게, 기울임, 인라인 코드, 링크, 이미지)
function parseInline(text) {
  // 백슬래시 이스케이프 먼저 처리
  text = processEscapes(text);

  // 인라인 코드 (`` ` `` 또는 ` `` `)
  text = text.replace(/``(.+?)``/g, (_, code) => `<code>${escapeHtml(code)}</code>`);
  text = text.replace(/`([^`]+)`/g, (_, code) => `<code>${escapeHtml(code)}</code>`);

  // 이미지 (링크보다 먼저 처리)
  text = text.replace(/!\[([^\]]*)\]\(([^)]+?)(?:\s+"([^"]*)")?\)/g, (_, alt, src, title) => {
    const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
    return `<img src="${escapeHtml(src)}" alt="${escapeHtml(alt)}"${titleAttr}>`;
  });

  // 링크
  text = text.replace(/\[([^\]]+)\]\(([^)]+?)(?:\s+"([^"]*)")?\)/g, (_, label, href, title) => {
    const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
    return `<a href="${escapeHtml(href)}"${titleAttr}>${label}</a>`;
  });

  // 굵게 + 기울임 (***text*** 또는 ___text___)
  text = text.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
  text = text.replace(/___(.+?)___/g, '<strong><em>$1</em></strong>');

  // 굵게 (**text** 또는 __text__)
  text = text.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  text = text.replace(/__(.+?)__/g, '<strong>$1</strong>');

  // 기울임 (*text* 또는 _text_)
  text = text.replace(/\*([^*]+)\*/g, '<em>$1</em>');
  text = text.replace(/_([^_]+)_/g, '<em>$1</em>');

  // 취소선 (~~text~~)
  text = text.replace(/~~(.+?)~~/g, '<del>$1</del>');

  // 자동 URL 링크
  text = text.replace(/(https?:\/\/[^\s<>"]+)/g, '<a href="$1">$1</a>');

  return text;
}

