// ═══════════════════════════════════════════════════════════════

function buildExportHtml(markdown) {
  const renderedBody = P.parse(markdown);
  return `<!DOCTYPE html>\n<html lang="ko">\n<head>\n  <meta charset="UTF-8">\n  <title>내보낸 문서</title>\n</head>\n<body>\n${renderedBody}\n</body>\n</html>`;
}

