   294→        continue;
   295→      }
   296→
   297→      // 인용문
   298→      if (/^>/.test(line)) {
   299→        flushParagraph();
   300→        const result = parseBlockquote(lines, i);
   301→        outputParts.push(result.html);
   302→        i = result.nextIndex;
   303→        continue;
   304→      }
   305→
   306→      // 목록
   307→      if (/^(\s*)[-*+]\s/.test(line) || /^(\s*)\d+\.\s/.test(line)) {
   308→        flushParagraph();
   309→        const result = parseList(lines, i);
   310→        outputParts.push(result.html);
   311→        i = result.nextIndex;
   312→        continue;
   313→      }
   314→
   315→      // 일반 텍스트 → 문단으로 수집
   316→      paragraphLines.push(line);
