     1→/**
     2→ * 에디터 로직
     3→ * - 실시간 미리보기 업데이트
     4→ * - 툴바 버튼 동작 (선택 텍스트 감싸기 / 커서 위치 삽입)
     5→ * - 드래그로 분할 창 크기 조정
     6→ * - 키보드 단축키 (Ctrl+B, Ctrl+I, Ctrl+K)
     7→ * - localStorage 자동 저장/복원
     8→ * - HTML 내보내기
     9→ */
    10→
    11→(function () {
    12→  'use strict';
    13→
    14→  // ===== DOM 요소 =====
    15→  const editor = document.getElementById('editor');
    16→  const preview = document.getElementById('preview');
    17→  const resizer = document.getElementById('resizer');
    18→  const editorPane = document.getElementById('editor-pane');
    19→  const previewPane = document.getElementById('preview-pane');
    20→  const editorContainer = document.getElementById('editor-container');
    21→  const exportBtn = document.getElementById('export-btn');
    22→  const saveStatus = document.getElementById('save-status');
    23→  const wordCount = document.getElementById('word-count');
    24→  const toast = document.getElementById('toast');
    25→
    26→  // ===== 상수 =====
    27→  const STORAGE_KEY = 'markdown-editor-content';
    28→  const SAVE_DEBOUNCE_MS = 800;
    29→  const PREVIEW_DEBOUNCE_MS = 150;
    30→  const MIN_PANE_WIDTH_PX = 80;
    31→
    32→  // ===== 초기 콘텐츠 =====
    33→  const DEFAULT_CONTENT = `# 마크다운 에디터에 오신 것을 환영합니다
    34→
    35→이것은 **라이브 미리보기**가 있는 마크다운 에디터입니다.
    36→
    37→## 사용법
    38→
    39→왼쪽 패널에서 마크다운을 작성하면 오른쪽에 실시간으로 렌더링됩니다.
    40→
    41→### 지원하는 서식
    42→
    43→- **굵게** \`**텍스트**\`
    44→- *기울임* \`*텍스트*\`
    45→- ***굵게+기울임*** \`***텍스트***\`
    46→- ~~취소선~~ \`~~텍스트~~\`
    47→- \`인라인 코드\`
    48→
    49→### 코드 블록
    50→
    51→\`\`\`javascript
    52→function greet(name) {
    53→  console.log(\`Hello, \${name}!\`);
    54→}
    55→greet('World');
    56→\`\`\`
    57→
    58→### 링크와 이미지
    59→
    60→[GitHub](https://github.com) 링크 예시
    61→
    62→### 목록
    63→
    64→1. 첫 번째 항목
    65→2. 두 번째 항목
    66→   - 중첩 항목 A
    67→   - 중첩 항목 B
    68→3. 세 번째 항목
    69→
    70→> 인용문 예시입니다.
    71→> 여러 줄도 지원합니다.
    72→
    73→---
    74→
    75→**Export HTML** 버튼으로 결과물을 다운로드할 수 있습니다.
    76→`;
    77→
    78→  // ===== 상태 =====
    79→  let saveTimer = null;
    80→  let previewTimer = null;
    81→  let isUnsaved = false;
    82→  let toastTimer = null;
    83→
    84→  // ===== 초기화 =====
    85→  function init() {
    86→    loadContent();
    87→    updatePreview();
    88→    updateWordCount();
    89→    setupToolbar();
    90→    setupResizer();
    91→    setupKeyboardShortcuts();
    92→    setupAutoSave();
    93→    setupExport();
    94→    setupScrollSync();
    95→  }
    96→
    97→  // ===== 콘텐츠 로드/저장 =====
    98→  function loadContent() {
    99→    try {
   100→      const saved = localStorage.getItem(STORAGE_KEY);
   101→      editor.value = saved !== null ? saved : DEFAULT_CONTENT;
   102→      setSaveStatus('saved');
   103→    } catch (e) {
   104→      editor.value = DEFAULT_CONTENT;
   105→    }
   106→  }
   107→
   108→  function saveContent() {
   109→    try {
   110→      localStorage.setItem(STORAGE_KEY, editor.value);
   111→      setSaveStatus('saved');
   112→      isUnsaved = false;
   113→    } catch (e) {
   114→      setSaveStatus('unsaved');
   115→      showToast('저장에 실패했습니다', 'error');
   116→    }
   117→  }
   118→
   119→  function setSaveStatus(status) {
   120→    if (!saveStatus) return;
   121→    if (status === 'saved') {
   122→      saveStatus.textContent = '저장됨';
   123→      saveStatus.className = 'saved';
   124→    } else if (status === 'unsaved') {
   125→      saveStatus.textContent = '저장 안 됨';
   126→      saveStatus.className = 'unsaved';
   127→    } else {
   128→      saveStatus.textContent = '저장 중...';
   129→      saveStatus.className = '';
   130→    }
   131→  }
   132→
   133→  // ===== 미리보기 업데이트 =====
   134→  function updatePreview() {
   135→    const markdown = editor.value;
   136→
   137→    if (!markdown.trim()) {
   138→      preview.innerHTML = `
   139→        <div id="preview-empty">
   140→          <div class="empty-icon">📝</div>
   141→          <p>왼쪽에 마크다운을 입력하면<br>여기에 미리보기가 표시됩니다</p>
   142→        </div>`;
   143→      return;
   144→    }
   145→
   146→    try {
   147→      preview.innerHTML = MarkdownParser.parse(markdown);
   148→    } catch (e) {
   149→      preview.innerHTML = `<p style="color: var(--accent-red)">파싱 오류: ${e.message}</p>`;
   150→    }
   151→  }
   152→
   153→  function schedulePreviewUpdate() {
   154→    clearTimeout(previewTimer);
   155→    previewTimer = setTimeout(updatePreview, PREVIEW_DEBOUNCE_MS);
   156→  }
   157→
   158→  // ===== 단어 수 계산 =====
   159→  function updateWordCount() {
   160→    if (!wordCount) return;
   161→    const text = editor.value.trim();
   162→    const chars = text.length;
   163→    const words = text ? text.split(/\s+/).filter(Boolean).length : 0;
   164→    const lines = editor.value.split('\n').length;
   165→    wordCount.textContent = `${lines}줄 · ${words}단어 · ${chars}자`;
   166→  }
   167→
   168→  // ===== 자동 저장 설정 =====
   169→  function setupAutoSave() {
   170→    editor.addEventListener('input', () => {
   171→      isUnsaved = true;
   172→      setSaveStatus('unsaved');
   173→      schedulePreviewUpdate();
   174→      updateWordCount();
   175→
   176→      clearTimeout(saveTimer);
   177→      saveTimer = setTimeout(saveContent, SAVE_DEBOUNCE_MS);
   178→    });
   179→  }
   180→
   181→  // ===== 커서/선택 영역 텍스트 삽입 유틸 =====
   182→  function getSelection() {
   183→    const start = editor.selectionStart;
   184→    const end = editor.selectionEnd;
   185→    return {
   186→      start,
   187→      end,
   188→      selected: editor.value.slice(start, end),
   189→      before: editor.value.slice(0, start),
   190→      after: editor.value.slice(end),
   191→    };
   192→  }
   193→
   194→  /**
   195→   * 선택된 텍스트를 prefix/suffix로 감싸거나,
   196→   * 선택이 없으면 cursor 위치에 placeholder를 삽입하고 선택
   197→   */
   198→  function wrapText(prefix, suffix, placeholder = '텍스트') {
   199→    const { start, end, selected, before, after } = getSelection();
   200→    const content = selected || placeholder;
   201→    const newText = before + prefix + content + suffix + after;
   202→    editor.value = newText;
   203→
   204→    const selStart = start + prefix.length;
   205→    const selEnd = selStart + content.length;
   206→    editor.setSelectionRange(selStart, selEnd);
   207→    editor.focus();
   208→    triggerUpdate();
   209→  }
   210→
   211→  /**
   212→   * 줄 앞에 prefix 삽입 (제목, 목록, 인용문 등)
   213→   */
   214→  function insertLinePrefix(prefix, placeholder = '') {
   215→    const { start, end, selected, before, after } = getSelection();
   216→
   217→    // 선택 영역이 있으면 각 줄에 prefix 추가
   218→    if (selected) {
   219→      const lines = selected.split('\n');
   220→      const prefixed = lines.map(line => prefix + line).join('\n');
   221→      editor.value = before + prefixed + after;
   222→      editor.setSelectionRange(start, start + prefixed.length);
   223→    } else {
   224→      // 현재 줄의 시작 위치 찾기
   225→      const lineStart = before.lastIndexOf('\n') + 1;
   226→      const lineContent = editor.value.slice(lineStart, end);
   227→      const newLine = prefix + (lineContent || placeholder);
   228→      editor.value = editor.value.slice(0, lineStart) + newLine + after;
   229→      editor.setSelectionRange(lineStart + prefix.length, lineStart + newLine.length);
   230→    }
   231→
   232→    editor.focus();
   233→    triggerUpdate();
   234→  }
   235→
   236→  /**
   237→   * 커서 위치에 블록 삽입 (코드블록, 수평선 등)
   238→   */
   239→  function insertBlock(text, cursorOffset = null) {
   240→    const { start, before, after } = getSelection();
   241→    // 줄 앞 개행 보장
   242→    const prefix = before.length > 0 && !before.endsWith('\n') ? '\n' : '';
   243→    const suffix = !after.startsWith('\n') ? '\n' : '';
   244→    const inserted = prefix + text + suffix;
   245→    editor.value = before + inserted + after;
   246→
   247→    const newPos = cursorOffset !== null
   248→      ? start + prefix.length + cursorOffset
   249→      : start + inserted.length;
   250→    editor.setSelectionRange(newPos, newPos);
   251→    editor.focus();
   252→    triggerUpdate();
   253→  }
   254→
   255→  function triggerUpdate() {
   256→    editor.dispatchEvent(new Event('input'));
   257→  }
   258→
   259→  // ===== 툴바 동작 정의 =====
   260→  const toolbarActions = {
   261→    bold:          () => wrapText('**', '**', '굵은 텍스트'),
   262→    italic:        () => wrapText('*', '*', '기울임 텍스트'),
   263→    heading1:      () => insertLinePrefix('# ', '제목 1'),
   264→    heading2:      () => insertLinePrefix('## ', '제목 2'),
   265→    heading3:      () => insertLinePrefix('### ', '제목 3'),
   266→    link:          () => {
   267→      const { selected } = getSelection();
   268→      const label = selected || '링크 텍스트';
   269→      if (selected) {
   270→        wrapText('[', '](URL)', label);
   271→      } else {
   272→        insertBlock('[링크 텍스트](URL)');
   273→      }
   274→    },
   275→    image:         () => insertBlock('![대체 텍스트](이미지-URL)'),
   276→    code:          () => {
   277→      const { selected } = getSelection();
   278→      if (selected && selected.includes('\n')) {
   279→        const lang = 'javascript';
   280→        insertBlock(`\`\`\`${lang}\n${selected}\n\`\`\``);
   281→      } else {
   282→        wrapText('`', '`', '코드');
   283→      }
   284→    },
   285→    codeblock:     () => insertBlock('```javascript\n코드를 입력하세요\n```', 14),
   286→    unordered:     () => insertLinePrefix('- ', '목록 항목'),
   287→    ordered:       () => insertLinePrefix('1. ', '목록 항목'),
   288→    blockquote:    () => insertLinePrefix('> ', '인용문'),
   289→    hr:            () => insertBlock('\n---\n'),
   290→  };
   291→
   292→  // ===== 툴바 이벤트 연결 =====
   293→  function setupToolbar() {
   294→    const toolbar = document.getElementById('toolbar');
   295→    if (!toolbar) return;
   296→
   297→    toolbar.addEventListener('click', (e) => {
   298→      const btn = e.target.closest('[data-action]');
   299→      if (!btn) return;
   300→      const action = btn.dataset.action;
   301→      if (toolbarActions[action]) {
   302→        toolbarActions[action]();
   303→      }
   304→    });
   305→  }
   306→
   307→  // ===== 키보드 단축키 =====
   308→  function setupKeyboardShortcuts() {
   309→    editor.addEventListener('keydown', (e) => {
   310→      const isMac = navigator.platform.toUpperCase().includes('MAC');
   311→      const ctrl = isMac ? e.metaKey : e.ctrlKey;
   312→
   313→      if (!ctrl) return;
   314→
   315→      switch (e.key.toLowerCase()) {
   316→        case 'b':
   317→          e.preventDefault();
   318→          toolbarActions.bold();
   319→          break;
   320→        case 'i':
   321→          e.preventDefault();
   322→          toolbarActions.italic();
   323→          break;
   324→        case 'k':
   325→          e.preventDefault();
   326→          toolbarActions.link();
   327→          break;
   328→        case 's':
   329→          e.preventDefault();
   330→          saveContent();
   331→          showToast('저장되었습니다', 'success');
   332→          break;
   333→        case 'z':
   334→          // 기본 실행취소 허용
   335→          break;
   336→      }
   337→    });
   338→
   339→    // Tab 키 → 2 스페이스 들여쓰기
   340→    editor.addEventListener('keydown', (e) => {
   341→      if (e.key === 'Tab') {
   342→        e.preventDefault();
   343→        const { start, end, before, after, selected } = getSelection();
   344→        if (selected && selected.includes('\n')) {
   345→          // 다중 줄 들여쓰기
   346→          const lines = selected.split('\n');
   347→          const indented = e.shiftKey
   348→            ? lines.map(l => l.startsWith('  ') ? l.slice(2) : l.startsWith('\t') ? l.slice(1) : l)
   349→            : lines.map(l => '  ' + l);
   350→          const result = indented.join('\n');
   351→          editor.value = before + result + after;
   352→          editor.setSelectionRange(start, start + result.length);
   353→        } else {
   354→          editor.value = before + '  ' + after;
   355→          editor.setSelectionRange(start + 2, start + 2);
   356→        }
   357→        triggerUpdate();
   358→      }
   359→    });
   360→  }
   361→
   362→  // ===== 드래그 리사이저 =====
   363→  function setupResizer() {
   364→    if (!resizer) return;
   365→
   366→    let isDragging = false;
   367→    let startX = 0;
   368→    let startEditorWidth = 0;
   369→    let isVertical = false;
   370→
   371→    resizer.addEventListener('mousedown', onDragStart);
   372→    resizer.addEventListener('touchstart', onDragStart, { passive: false });
   373→
   374→    function onDragStart(e) {
   375→      isDragging = true;
   376→      resizer.classList.add('dragging');
   377→      document.body.style.cursor = 'col-resize';
   378→      document.body.style.userSelect = 'none';
   379→
   380→      const containerRect = editorContainer.getBoundingClientRect();
   381→      isVertical = containerRect.width < containerRect.height * 1.5 && window.innerWidth <= 768;
   382→
   383→      if (e.type === 'touchstart') {
   384→        startX = e.touches[0].clientX;
   385→      } else {
   386→        startX = e.clientX;
   387→        e.preventDefault();
   388→      }
   389→
   390→      startEditorWidth = editorPane.getBoundingClientRect().width;
   391→
   392→      document.addEventListener('mousemove', onDragMove);
   393→      document.addEventListener('mouseup', onDragEnd);
   394→      document.addEventListener('touchmove', onDragMove, { passive: false });
   395→      document.addEventListener('touchend', onDragEnd);
   396→    }
   397→
   398→    function onDragMove(e) {
   399→      if (!isDragging) return;
   400→      if (e.type === 'touchmove') e.preventDefault();
   401→
   402→      const clientX = e.type === 'touchmove' ? e.touches[0].clientX : e.clientX;
   403→      const delta = clientX - startX;
   404→      const containerWidth = editorContainer.getBoundingClientRect().width;
   405→      const resizerWidth = resizer.getBoundingClientRect().width;
   406→      const availableWidth = containerWidth - resizerWidth;
   407→
   408→      let newEditorWidth = startEditorWidth + delta;
   409→      newEditorWidth = Math.max(MIN_PANE_WIDTH_PX, Math.min(newEditorWidth, availableWidth - MIN_PANE_WIDTH_PX));
   410→
   411→      const editorPercent = (newEditorWidth / availableWidth) * 100;
   412→      const previewPercent = 100 - editorPercent;
   413→
   414→      editorPane.style.flex = 'none';
   415→      editorPane.style.width = `${editorPercent}%`;
   416→      previewPane.style.flex = 'none';
   417→      previewPane.style.width = `${previewPercent}%`;
   418→    }
   419→
   420→    function onDragEnd() {
   421→      isDragging = false;
   422→      resizer.classList.remove('dragging');
   423→      document.body.style.cursor = '';
   424→      document.body.style.userSelect = '';
   425→
   426→      document.removeEventListener('mousemove', onDragMove);
   427→      document.removeEventListener('mouseup', onDragEnd);
   428→      document.removeEventListener('touchmove', onDragMove);
   429→      document.removeEventListener('touchend', onDragEnd);
   430→    }
   431→
   432→    // 더블클릭으로 50/50 초기화
   433→    resizer.addEventListener('dblclick', () => {
   434→      editorPane.style.flex = '1';
   435→      editorPane.style.width = '';
   436→      previewPane.style.flex = '1';
   437→      previewPane.style.width = '';
   438→    });
   439→  }
   440→
   441→  // ===== 스크롤 동기화 =====
   442→  function setupScrollSync() {
   443→    let syncingEditor = false;
   444→    let syncingPreview = false;
   445→
   446→    editor.addEventListener('scroll', () => {
   447→      if (syncingEditor) return;
   448→      syncingPreview = true;
   449→
   450→      const editorScrollRatio = editor.scrollTop / (editor.scrollHeight - editor.clientHeight || 1);
   451→      const previewScrollMax = preview.scrollHeight - preview.clientHeight;
   452→      preview.scrollTop = editorScrollRatio * previewScrollMax;
   453→
   454→      requestAnimationFrame(() => { syncingPreview = false; });
   455→    });
   456→
   457→    preview.addEventListener('scroll', () => {
   458→      if (syncingPreview) return;
   459→      syncingEditor = true;
   460→
   461→      const previewScrollRatio = preview.scrollTop / (preview.scrollHeight - preview.clientHeight || 1);
   462→      const editorScrollMax = editor.scrollHeight - editor.clientHeight;
   463→      editor.scrollTop = previewScrollRatio * editorScrollMax;
   464→
   465→      requestAnimationFrame(() => { syncingEditor = false; });
   466→    });
   467→  }
   468→
   469→  // ===== HTML 내보내기 =====
   470→  function setupExport() {
   471→    if (!exportBtn) return;
   472→    exportBtn.addEventListener('click', exportHtml);
   473→  }
   474→
   475→  function exportHtml() {
   476→    const markdown = editor.value;
   477→    const renderedBody = MarkdownParser.parse(markdown);
   478→
   479→    const html = `<!DOCTYPE html>
   480→<html lang="ko">
   481→<head>
   482→  <meta charset="UTF-8">
   483→  <meta name="viewport" content="width=device-width, initial-scale=1.0">
   484→  <title>내보낸 문서</title>
   485→  <style>
   486→    :root {
   487→      --bg: #0d1117;
   488→      --text: #e6edf3;
   489→      --text-muted: #8b949e;
   490→      --border: #30363d;
   491→      --accent: #58a6ff;
   492→      --code-bg: #161b22;
   493→      --pre-bg: #161b22;
   494→      --blockquote-border: #388bfd;
   495→    }
   496→    body {
   497→      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Helvetica, Arial, sans-serif;
   498→      background: var(--bg);
   499→      color: var(--text);
   500→      max-width: 800px;
   501→      margin: 0 auto;
   502→      padding: 48px 32px;
   503→      line-height: 1.7;
   504→      font-size: 16px;
   505→    }
   506→    h1, h2, h3, h4, h5, h6 { margin: 24px 0 16px; font-weight: 600; line-height: 1.25; }
   507→    h1 { font-size: 2em; padding-bottom: 0.3em; border-bottom: 1px solid var(--border); }
   508→    h2 { font-size: 1.5em; padding-bottom: 0.3em; border-bottom: 1px solid var(--border); }
   509→    h3 { font-size: 1.25em; }
   510→    p { margin: 0 0 16px; }
   511→    a { color: var(--accent); text-decoration: none; }
   512→    a:hover { text-decoration: underline; }
   513→    strong { font-weight: 700; }
   514→    code {
   515→      font-family: 'JetBrains Mono', 'Fira Code', monospace;
   516→      font-size: 0.875em;
   517→      background: var(--code-bg);
   518→      color: #f08080;
   519→      padding: 0.2em 0.4em;
   520→      border-radius: 4px;
   521→      border: 1px solid var(--border);
   522→    }
   523→    pre {
   524→      background: var(--pre-bg);
   525→      border: 1px solid var(--border);
   526→      border-radius: 6px;
   527→      overflow: hidden;
   528→      margin: 16px 0;
   529→    }
   530→    pre .code-lang {
   531→      display: block;
   532→      padding: 6px 16px;
   533→      background: #0d1117;
   534→      border-bottom: 1px solid var(--border);
   535→      font-family: monospace;
   536→      font-size: 11px;
   537→      color: var(--text-muted);
   538→      text-transform: uppercase;
   539→      letter-spacing: 0.5px;
   540→    }
   541→    pre code {
   542→      display: block;
   543→      padding: 16px;
   544→      background: transparent;
   545→      color: var(--text);
   546→      border: none;
   547→      font-size: 13px;
   548→      line-height: 1.6;
   549→      overflow-x: auto;
   550→      white-space: pre;
   551→    }
   552→    ul, ol { padding-left: 2em; margin-bottom: 16px; }
   553→    li { margin-bottom: 4px; }
   554→    blockquote {
   555→      margin: 16px 0;
   556→      padding: 12px 20px;
   557→      border-left: 4px solid var(--blockquote-border);
   558→      background: rgba(56,139,253,0.06);
   559→      border-radius: 0 6px 6px 0;
   560→      color: var(--text-muted);
   561→    }
   562→    hr { border: none; height: 2px; background: var(--border); margin: 24px 0; }
   563→    img { max-width: 100%; border-radius: 6px; border: 1px solid var(--border); }
   564→    del { color: var(--text-muted); text-decoration: line-through; }
   565→  </style>
   566→</head>
   567→<body>
   568→${renderedBody}
   569→</body>
   570→</html>`;
   571→
   572→    const blob = new Blob([html], { type: 'text/html;charset=utf-8' });
   573→    const url = URL.createObjectURL(blob);
   574→    const a = document.createElement('a');
   575→    a.href = url;
   576→    a.download = 'document.html';
   577→    a.click();
   578→    URL.revokeObjectURL(url);
   579→    showToast('HTML 파일이 다운로드되었습니다', 'success');
   580→  }
   581→
   582→  // ===== 토스트 알림 =====
   583→  function showToast(message, type = 'info') {
   584→    if (!toast) return;
   585→    clearTimeout(toastTimer);
   586→    toast.textContent = message;
   587→    toast.className = `show ${type}`;
   588→    toastTimer = setTimeout(() => {
   589→      toast.className = toast.className.replace('show', '').trim();
   590→    }, 2500);
   591→  }
   592→
   593→  // ===== 페이지 이탈 경고 =====
   594→  window.addEventListener('beforeunload', (e) => {
   595→    if (isUnsaved) {
   596→      e.preventDefault();
   597→      e.returnValue = '';
   598→    }
   599→  });
   600→
   601→  // ===== 실행 =====
   602→  document.addEventListener('DOMContentLoaded', init);
   603→
   604→})();
   605→

